mapper.select:
select q.*, qa.id qa_id, qa.question_id, qa.answer, qa.keywords, qa.create_time qa_create_time, qa.update_time qa_update_time, qa.is_deleted qa_is_deleted
 from questions q inner join question_answers qa
 on q.id = qa.question_id
 where q.is_deleted = 0 and qa.is_deleted = 0

    and q.category_id = #{queryVo.categoryId}


     and q.difficulty = #{queryVo.difficulty}


     and q.type = #{queryVo.type}


     and q.title like concat('%',#{queryVo.keyword},'%')

 order by q.create_time desc
